import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Constructor;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setup() {
        csvFormat = new CSVFormat(',', '"', QuoteMode.MINIMAL, '#', '\\', true, false, "\r\n", "\\N",
                new Object[] { "Header1", "Header2" }, new String[] { "Comment1", "Comment2" }, true, false, true, false,
                true);
    }

    @Test
    public void testGetIgnoreSurroundingSpaces() {
        // Given
        boolean expected = true;

        // When
        boolean result = csvFormat.getIgnoreSurroundingSpaces();

        // Then
        assertEquals(expected, result);
    }

    @Test
    public void testGetIgnoreSurroundingSpacesPrivateConstructor() throws Exception {
        // Given
        boolean expected = true;

        // Mocking private constructor
        CSVFormat csvFormatMock = mock(CSVFormat.class);
        when(csvFormatMock.getIgnoreSurroundingSpaces()).thenReturn(true);

        // Using reflection to access private constructor
        Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(char.class, Character.class, QuoteMode.class, Character.class,
                Character.class, boolean.class, boolean.class, String.class, String.class, Object[].class, String[].class,
                boolean.class, boolean.class, boolean.class, boolean.class, boolean.class);
        constructor.setAccessible(true);
        csvFormat = constructor.newInstance(',', '"', QuoteMode.MINIMAL, '#', '\\', true, false, "\r\n", "\\N",
                        new Object[] { "Header1", "Header2" }, new String[] { "Comment1", "Comment2" }, true, false, true, false,
                        true);

        // When
        boolean result = csvFormat.getIgnoreSurroundingSpaces();

        // Then
        assertEquals(expected, result);
    }
}
